// Extract and store variables for use throughout the workflow
const item = $input.first().json;

return [{
  json: {
    execution_id: item.execution_id,
    callback_url: item.callback_url || null,
    scene: item.scene,
    scene_id: String(item.scene.id).padStart(2, '0'),
    video_model: item.config?.video_model || 'kling-2.6',
    motion_strength: item.config?.motion_strength || 'medium',
    fps: item.config?.fps || 24,
    s3_path: `${item.execution_id}/videos/scene_${String(item.scene.id).padStart(2, '0')}.mp4`
  }
}];

// Build the motion prompt from scene data and frame context
const scene = $input.first().json.scene;
const motionStrength = $('Set Variables').first().json.motion_strength;

const motionPrompt = [
  'Smooth camera motion from start to end position.',
  `Scene: ${scene.description}`,
  `Motion intensity: ${motionStrength}`,
  `Camera movement: ${scene.frame_descriptions?.start_frame?.composition || 'static to dynamic'}`,
  'Maintain character consistency throughout.',
  'Cinematic quality, professional video production.'
].join('\n').trim();

return [{
  json: {
    motion_prompt: motionPrompt,
    start_frame_url: scene.start_frame_url,
    end_frame_url: scene.end_frame_url,
    duration: scene.duration_seconds
  }
}];

