// Poll Wavespeed AI for video generation completion
const item = $input.first().json;
const predictionId = item.body?.id || item.id;

if (!predictionId) {
  throw new Error('No prediction ID returned from Wavespeed AI');
}

const maxAttempts = 20; // 20 * 30s = 10 minutes max
const delayMs = 30000; // 30 seconds

for (let attempt = 0; attempt < maxAttempts; attempt++) {
  const response = await this.helpers.httpRequest({
    method: 'GET',
    url: `https://api.wavespeed.ai/api/v3/predictions/${predictionId}`,
    headers: {
      'Authorization': `Bearer ${$credentials.wavespeedApiKey}`
    }
  });

  if (response.status === 'succeeded') {
    const videoUrl = response.output?.video_url || response.output;
    if (!videoUrl) {
      throw new Error('Wavespeed succeeded but returned no video URL');
    }
    return [{
      json: {
        success: true,
        video_url: videoUrl,
        prediction_id: predictionId,
        provider: 'wavespeed',
        processing_time: attempt * 30
      }
    }];
  }

  if (response.status === 'failed') {
    throw new Error(`Wavespeed video generation failed: ${response.error || 'Unknown error'}`);
  }

  // Status is still 'processing' or 'starting' - keep polling
  await new Promise(resolve => setTimeout(resolve, delayMs));
}

throw new Error('Wavespeed video generation timeout after 10 minutes');

