// Poll Runway API for video generation completion
const item = $input.first().json;
const taskId = item.body?.id || item.id;

if (!taskId) {
  throw new Error('No task ID returned from Runway API');
}

const maxAttempts = 40; // Runway can take longer
const delayMs = 15000; // 15 seconds

for (let attempt = 0; attempt < maxAttempts; attempt++) {
  const response = await this.helpers.httpRequest({
    method: 'GET',
    url: `https://api.runwayml.com/v1/tasks/${taskId}`,
    headers: {
      'Authorization': `Bearer ${$credentials.runwayApiKey}`
    }
  });

  if (response.status === 'SUCCEEDED') {
    const videoUrl = response.output?.[0];
    if (!videoUrl) {
      throw new Error('Runway succeeded but returned no video URL');
    }
    return [{
      json: {
        success: true,
        video_url: videoUrl,
        task_id: taskId,
        provider: 'runway',
        processing_time: attempt * 15
      }
    }];
  }

  if (response.status === 'FAILED') {
    throw new Error(`Runway video generation failed: ${response.failure || 'Unknown error'}`);
  }

  // Still processing - keep polling
  await new Promise(resolve => setTimeout(resolve, delayMs));
}

throw new Error('Runway video generation timeout after 10 minutes');

