// Poll Kling API for video generation completion
const item = $input.first().json;
const taskId = item.body?.data?.task_id || item.data?.task_id || item.body?.task_id;

if (!taskId) {
  throw new Error('No task ID returned from Kling API');
}

const maxAttempts = 30;
const delayMs = 20000; // 20 seconds

for (let attempt = 0; attempt < maxAttempts; attempt++) {
  const response = await this.helpers.httpRequest({
    method: 'GET',
    url: `https://api.klingai.com/v1/videos/image2video/${taskId}`,
    headers: {
      'Authorization': `Bearer ${$credentials.klingApiKey}`
    }
  });

  const taskStatus = response.data?.task_status || response.task_status;

  if (taskStatus === 'succeed') {
    const videoUrl = response.data?.task_result?.videos?.[0]?.url ||
                     response.task_result?.videos?.[0]?.url;
    if (!videoUrl) {
      throw new Error('Kling succeeded but returned no video URL');
    }
    return [{
      json: {
        success: true,
        video_url: videoUrl,
        task_id: taskId,
        provider: 'kling',
        processing_time: attempt * 20
      }
    }];
  }

  if (taskStatus === 'failed') {
    throw new Error(`Kling video generation failed: ${response.data?.task_status_msg || 'Unknown error'}`);
  }

  // Still processing - keep polling
  await new Promise(resolve => setTimeout(resolve, delayMs));
}

throw new Error('Kling video generation timeout after 10 minutes');

// Download the generated video as binary data
const item = $input.first().json;
const videoUrl = item.video_url;

if (!videoUrl) {
  throw new Error('No video URL provided for download');
}

const videoBuffer = await this.helpers.httpRequest({
  method: 'GET',
  url: videoUrl,
  encoding: 'arraybuffer',
  timeout: 120000 // 2 minute timeout for large videos
});

return [{
  json: {
    video_data: Buffer.from(videoBuffer).toString('base64'),
    video_size: videoBuffer.length,
    source_url: videoUrl,
    provider: item.provider
  }
}];

// Upload the generated video to S3
const item = $input.first().json;
const vars = $('Set Variables').first().json;
const s3Bucket = $env.S3_BUCKET || 'vdo-gen';
const s3Region = $env.S3_REGION || 'us-east-1';
const s3Key = vars.s3_path;

if (!item.video_data) {
  throw new Error('No video data available for upload');
}

const videoBuffer = Buffer.from(item.video_data, 'base64');
const s3Url = `https://${s3Bucket}.s3.${s3Region}.amazonaws.com/${s3Key}`;

// Attempt upload with retry logic (3 retries with exponential backoff)
let uploaded = false;
let lastError = null;

for (let attempt = 0; attempt < 3; attempt++) {
  try {
    if (attempt > 0) {
      await new Promise(resolve => setTimeout(resolve, 2000 * Math.pow(2, attempt)));
    }

    await this.helpers.httpRequest({
      method: 'PUT',
      url: s3Url,
      headers: {
        'Content-Type': 'video/mp4',
        'x-amz-acl': 'public-read'
      },
      body: videoBuffer,
      encoding: 'arraybuffer',
      timeout: 300000 // 5 minutes for upload
    });

    uploaded = true;
    break;
  } catch (err) {
    lastError = err;
  }
}

if (!uploaded) {
  throw new Error(`S3 upload failed after 3 attempts: ${lastError?.message || 'Unknown error'}`);
}

return [{
  json: {
    scene_id: vars.scene.id,
    scene_title: vars.scene.title,
    video_url: s3Url,
    duration_seconds: vars.scene.duration_seconds,
    file_size_bytes: item.video_size,
    provider: item.provider,
    generated_at: new Date().toISOString()
  }
}];

